function calculate({ upfrontCost, estimatedAnnualEnergySavings, annualMaintenanceCost, potentialDamageCost, annualDamageProbability, lifespanYears, discountRate, annualEnergyCostIncreaseRate }) {

    if (upfrontCost <= 0) {
        return {
            calculatedTotalUpfrontCost: upfrontCost,
            estimatedFirstYearNetSavings: 0,
            paybackPeriodYears: Infinity,
            totalSavingsOverLifespan: 0,
            roiPercentage: 0,
            netPresentValue: -upfrontCost,
            error: "Upfront cost must be greater than zero."
        };
    }
    if (lifespanYears <= 0) {
        return {
            calculatedTotalUpfrontCost: upfrontCost,
            estimatedFirstYearNetSavings: 0,
            paybackPeriodYears: Infinity,
            totalSavingsOverLifespan: 0,
            roiPercentage: -100,
            netPresentValue: -upfrontCost,
            error: "Lifespan must be greater than zero."
        };
    }

    const annualDamageProbabilityDecimal = annualDamageProbability / 100;
    const discountRateDecimal = discountRate / 100;
    const annualEnergyCostIncreaseRateDecimal = annualEnergyCostIncreaseRate / 100;

    const annualAvoidedDamageCost = potentialDamageCost * annualDamageProbabilityDecimal;

    const firstYearNetSavings = estimatedAnnualEnergySavings + annualAvoidedDamageCost - annualMaintenanceCost;

    let paybackPeriodYears = Infinity;
    if (firstYearNetSavings > 0) {
        paybackPeriodYears = upfrontCost / firstYearNetSavings;
    } else if (firstYearNetSavings <= 0) {
         // If first-year savings are zero or negative, payback is not achieved within one year.
         // We need to check if it becomes positive later due to energy cost increases.
         // For simplicity, if first year is <= 0, we can assume very long or no payback.
         // More complex calculation would involve iterative payback period.
         // For this calculator, we'll mark as 'Not Achievable' if simple payback fails.
         // A more detailed check below for cumulative savings will determine if total savings ever exceed cost.
    }

    let totalUndiscountedSavings = 0;
    let npv = -upfrontCost;

    for (let year = 1; year <= lifespanYears; year++) {
        const energySavingsThisYear = estimatedAnnualEnergySavings * Math.pow(1 + annualEnergyCostIncreaseRateDecimal, year - 1);
        const maintenanceCostThisYear = annualMaintenanceCost; // Assuming maintenance cost does not inflate, or at least not at energy rate.
        const avoidedDamageThisYear = annualAvoidedDamageCost; // Assuming fixed expected avoided damage cost.

        const netCashFlowThisYear = energySavingsThisYear + avoidedDamageThisYear - maintenanceCostThisYear;
        totalUndiscountedSavings += netCashFlowThisYear;

        npv += netCashFlowThisYear / Math.pow(1 + discountRateDecimal, year);
    }

    let roiPercentage = -100; // Default for no savings
    if (upfrontCost > 0) {
        roiPercentage = ((totalUndiscountedSavings - upfrontCost) / upfrontCost) * 100;
    }

    if (firstYearNetSavings <= 0 && totalUndiscountedSavings < upfrontCost) {
        paybackPeriodYears = Infinity; // Explicitly set to Infinity if savings don't cover costs.
    } else if (firstYearNetSavings <= 0 && totalUndiscountedSavings >= upfrontCost) {
        // This case indicates that first-year net savings are negative or zero, but over the lifespan,
        // cumulative savings eventually exceed upfront costs (due to energy inflation, for example).
        // We'll calculate an iterative payback period for this specific scenario.
        let cumulativeSavingsForPayback = 0;
        for (let year = 1; year <= lifespanYears; year++) {
            const energySavingsThisYear = estimatedAnnualEnergySavings * Math.pow(1 + annualEnergyCostIncreaseRateDecimal, year - 1);
            const maintenanceCostThisYear = annualMaintenanceCost;
            const avoidedDamageThisYear = annualAvoidedDamageCost;
            const netCashFlowThisYear = energySavingsThisYear + avoidedDamageThisYear - maintenanceCostThisYear;
            cumulativeSavingsForPayback += netCashFlowThisYear;
            if (cumulativeSavingsForPayback >= upfrontCost) {
                paybackPeriodYears = year; // Simple cumulative payback, without interpolation.
                break;
            }
            if (year === lifespanYears) {
                paybackPeriodYears = Infinity; // Still didn't pay back within lifespan.
            }
        }
    }

    return {
        calculatedTotalUpfrontCost: upfrontCost,
        estimatedFirstYearNetSavings: firstYearNetSavings,
        paybackPeriodYears: paybackPeriodYears,
        totalSavingsOverLifespan: totalUndiscountedSavings,
        roiPercentage: roiPercentage,
        netPresentValue: npv
    };
}
